import{_ as t,c as e,o as a,a as n}from"./app.3fdcf20e.js";const f=JSON.parse('{"title":"OpenShield-XDP","description":"","frontmatter":{},"headers":[{"level":2,"title":"Detection Surface","slug":"detection-surface","link":"#detection-surface","children":[]},{"level":2,"title":"Mitigation","slug":"mitigation","link":"#mitigation","children":[]},{"level":2,"title":"Performance","slug":"performance","link":"#performance","children":[]}],"relativePath":"openshield-xdp/index.md","lastUpdated":1782412920000}'),i={name:"openshield-xdp/index.md"},s=n(`<h1 id="openshield-xdp" tabindex="-1">OpenShield-XDP <a class="header-anchor" href="#openshield-xdp" aria-hidden="true">#</a></h1><p>XDP-native DDoS mitigation at line rate.</p><p>Inspects and drops attack traffic inside the NIC driver \u2014 before the kernel allocates an skb, before iptables runs, before your application sees anything.</p><p>A single attached core handles <strong>10M+ packets per second</strong>. Suspicion scoring, SYN cookies, L7 pattern matching, UDP amplification detection, entropy-based spoofing, and autonomous subnet escalation all run without a context switch.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">git clone https://github.com/AnAverageBeing/OpenShield-XDP.git</span></span>
<span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> OpenShield-XDP </span><span style="color:#89DDFF;">&amp;&amp;</span><span style="color:#A6ACCD;"> ./install.sh</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo openshield load</span></span>
<span class="line"></span></code></pre></div><h2 id="detection-surface" tabindex="-1">Detection Surface <a class="header-anchor" href="#detection-surface" aria-hidden="true">#</a></h2><p>OpenShield classifies <strong>42 attack vectors</strong> across 7 layers.</p><table><thead><tr><th>Layer</th><th>Vectors</th></tr></thead><tbody><tr><td>L2 \u2014 Ethernet / MAC</td><td>Blacklist, whitelist, 802.1Q / 802.1ad / QinQ</td></tr><tr><td>L3 \u2014 IP validation</td><td>IPv4 private/bogon (7 ranges), IPv6 private/bogon (6 ranges), malformed headers</td></tr><tr><td>L4 \u2014 TCP/UDP flags</td><td>Bogus flags (5 combos), L4 header bounds, TCP doff validation</td></tr><tr><td>Rate-based per IP</td><td>PPS, BPS, TCP, UDP, ICMP, SYN \u2014 6 metrics with additive scoring</td></tr><tr><td>Connection tracking</td><td>Blind SYN-ACK, blind RST, per-IP SYN timestamp</td></tr><tr><td>Amplification &amp; L7</td><td>DNS, generic UDP (8 ports), L7 signature matching (16 rules)</td></tr><tr><td>Statistical anomaly</td><td>SYN/FIN ratio, entropy spoofing, TTL anomaly, packet size anomaly, connection rate</td></tr></tbody></table><h2 id="mitigation" tabindex="-1">Mitigation <a class="header-anchor" href="#mitigation" aria-hidden="true">#</a></h2><ul><li><strong>Ban system</strong> \u2014 single IP, LPM subnet, auto /24 escalation, 6-level star system</li><li><strong>Rate limiting</strong> \u2014 threshold scoring or token bucket</li><li><strong>Whitelist</strong> \u2014 per-IP flags (full bypass, skip ban, skip rate, skip validation)</li><li><strong>SYNPROXY</strong> \u2014 cookie-based SYN flood mitigation at XDP line rate</li><li><strong>Panic circuit breaker</strong> \u2014 per-CPU probabilistic bulk drop</li></ul><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-hidden="true">#</a></h2><table><thead><tr><th>Stage</th><th>Latency</th></tr></thead><tbody><tr><td>Normal path (all passes)</td><td>~300\u2013500 ns</td></tr><tr><td>Attack path (all modules active)</td><td>~1\u20132 \u03BCs</td></tr><tr><td>At 10M PPS</td><td>~50\u201370% single-core utilization</td></tr></tbody></table><p><a href="https://github.com/AnAverageBeing/OpenShield-XDP" target="_blank" rel="noreferrer">Repository</a> \xB7 <a href="https://discord.gg/qgBMREWWgp" target="_blank" rel="noreferrer">Discord</a></p>`,13),r=[s];function o(d,l,c,p,h,g){return a(),e("div",null,r)}const m=t(i,[["render",o]]);export{f as __pageData,m as default};
